// Extrai dados da mensagem do payload WhatsApp Cloud API
const body = $input.first().json

const entry = body?.entry?.[0]
const change = entry?.changes?.[0]
const value = change?.value
const message = value?.messages?.[0]

if (!message) {
  // Sem mensagem (pode ser status update)
  return []
}

const phone = message.from
const incomingText = (message.text?.body ?? '').trim().toLowerCase()
const messageId = message.id
const timestamp = message.timestamp

return [{
  json: {
    phone,
    incomingText,
    messageId,
    timestamp,
    rawMessage: message,
    businessPhone: value?.metadata?.phone_number_id,
  }
}]

// ATENÇÃO: Este código é gerado automaticamente por scripts/build-workflow.js
// Execute: node scripts/build-workflow.js para atualizar

// ─── Contexto da sessão ───
const messageData = $input.first().json
const phone = messageData.phone
const incomingText = messageData.incomingText
const messageId = messageData.messageId

const sessionRow = $('Buscar Sessão').first()?.json
const currentState = sessionRow?.current_state ?? 'new'
const context = sessionRow?.context ?? {}

const isGreeting = /^(oi|olá|ola|alo|hey|hi|hello|bom dia|boa tarde|boa noite|inicio|início|start)$/i.test(incomingText)
const isCancel = /^(cancelar|cancel|sair|exit|parar|stop)$/i.test(incomingText)
const isRestart = /^(recomeçar|recomecar|restart|novo|nova simulação|nova simulacao)$/i.test(incomingText)

const FINANCING_TYPE_MAP = {
  '1': 'imobiliario', 'imobiliario': 'imobiliario', 'imóvel': 'imobiliario', 'imovel': 'imobiliario', 'casa': 'imobiliario', 'apartamento': 'imobiliario',
  '2': 'veiculo', 'veiculo': 'veiculo', 'veículo': 'veiculo', 'carro': 'veiculo', 'moto': 'veiculo', 'caminhao': 'veiculo',
  '3': 'pessoal', 'pessoal': 'pessoal', 'empréstimo pessoal': 'pessoal', 'emprestimo pessoal': 'pessoal',
  '4': 'consignado', 'consignado': 'consignado',
  '5': 'empresa', 'empresa': 'empresa', 'pj': 'empresa', 'empresarial': 'empresa',
  '6': 'equipamento', 'equipamento': 'equipamento', 'maquinario': 'equipamento', 'máquina': 'equipamento',
  '7': 'rural', 'rural': 'rural', 'agrícola': 'rural', 'agricola': 'rural',
}

const TERM_SHORTCUTS = { '1': 12, '2': 24, '3': 36, '4': 48, '5': 60 }
const VALID_STATES = ['AC','AL','AP','AM','BA','CE','DF','ES','GO','MA','MT','MS','MG','PA','PB','PR','PE','PI','RJ','RN','RS','RO','RR','SC','SP','SE','TO']

function isValidCPF(cpf) {
  const clean = cpf.replace(/\D/g, '')
  if (clean.length !== 11 || /^(\d)\1+$/.test(clean)) return false
  let sum = 0
  for (let i = 0; i < 9; i++) sum += parseInt(clean[i]) * (10 - i)
  let r = (sum * 10) % 11
  if (r === 10 || r === 11) r = 0
  if (r !== parseInt(clean[9])) return false
  sum = 0
  for (let i = 0; i < 10; i++) sum += parseInt(clean[i]) * (11 - i)
  r = (sum * 10) % 11
  if (r === 10 || r === 11) r = 0
  return r === parseInt(clean[10])
}

function parseAmount(text) {
  const clean = text.replace(/[^0-9,.]/g, '').replace('.', '').replace(',', '.')
  return parseFloat(clean)
}

function formatCurrency(value) {
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value)
}

const CIVIL_STATUS_MAP = { '1': 'solteiro', '2': 'casado', '3': 'divorciado', '4': 'viuvo', '5': 'uniao_estavel' }
const PROPERTY_TYPE_MAP = { '1': 'residencial', '2': 'comercial', '3': 'terreno', '4': 'rural' }
const VEHICLE_TYPE_MAP = { '1': 'carro', '2': 'moto', '3': 'caminhao', '4': 'outro' }
const EMPLOYMENT_TYPE_MAP = { '1': 'clt', '2': 'servidor_publico', '3': 'autonomo', '4': 'empresario', '5': 'aposentado' }

// ─── Handlers ───

// GlobalHandler
let routerResult = null

if (isCancel && currentState !== 'new') {
  routerResult = {
    response: 'Atendimento encerrado. Digite "oi" quando quiser fazer uma nova simulação.',
    newState: 'abandoned',
    newContext: context,
    handled: true,
  }
}

if (!routerResult && isRestart) {
  routerResult = {
    response: '🔄 Vamos recomeçar! De qual modalidade você precisa?\n\n1️⃣ Imóvel\n2️⃣ Veículo\n3️⃣ Crédito Pessoal\n4️⃣ Consignado\n5️⃣ Empresa/PJ\n6️⃣ Equipamento\n7️⃣ Rural/Agrícola',
    newState: 'awaiting_financing_type',
    newContext: {},
    handled: true,
  }
}

// GreetingHandler
if (!routerResult && (currentState === 'new' || isGreeting)) {
  if (currentState !== 'new' && currentState !== 'completed' && currentState !== 'abandoned') {
    routerResult = {
      response: `Bem-vindo de volta, ${context.name ?? 'cliente'}! 👋\n\nVocê tinha uma simulação em andamento. Deseja continuar de onde parou?\n\n1️⃣ Continuar\n2️⃣ Recomeçar`,
      newState: currentState,
      newContext: context,
      handled: true,
    }
  } else {
    routerResult = {
      response: '👋 Olá! Seja bem-vindo ao simulador de financiamentos!\n\nPosso te ajudar a simular as melhores condições de financiamento nos principais bancos do mercado.\n\nQual modalidade você precisa?\n\n1️⃣ Imóvel\n2️⃣ Veículo\n3️⃣ Crédito Pessoal\n4️⃣ Consignado\n5️⃣ Empresa/PJ\n6️⃣ Equipamento\n7️⃣ Rural/Agrícola',
      newState: 'awaiting_financing_type',
      newContext: {},
      handled: true,
    }
  }
}

// FinancingTypeHandler
if (!routerResult && currentState === 'awaiting_financing_type') {
  const type = FINANCING_TYPE_MAP[incomingText]
  if (!type) {
    routerResult = {
      response: '❌ Opção inválida. Por favor, escolha uma das opções:\n\n1️⃣ Imóvel\n2️⃣ Veículo\n3️⃣ Crédito Pessoal\n4️⃣ Consignado\n5️⃣ Empresa/PJ\n6️⃣ Equipamento\n7️⃣ Rural/Agrícola',
      newState: currentState,
      newContext: context,
      handled: true,
    }
  } else {
    routerResult = {
      response: `Ótimo! Você escolheu *${type.charAt(0).toUpperCase() + type.slice(1)}* 👍\n\nAgora vou precisar de alguns dados seus.\n\nQual é o seu *nome completo*?`,
      newState: 'awaiting_name',
      newContext: { financingType: type },
      handled: true,
    }
  }
}

// PersonalDataHandler
if (!routerResult) {
  const personalStates = ['awaiting_name','awaiting_cpf','awaiting_birth_date','awaiting_civil_status','awaiting_email','awaiting_city','awaiting_state']
  if (personalStates.includes(currentState)) {
    if (currentState === 'awaiting_name') {
      if (incomingText.length < 3 || !incomingText.includes(' ')) {
        routerResult = { response: '❌ Por favor, informe seu nome completo (nome e sobrenome):', newState: currentState, newContext: context, handled: true }
      } else {
        const name = incomingText.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ')
        routerResult = { response: `Obrigado, ${name}! 😊\n\nQual é o seu *CPF*? (somente números)`, newState: 'awaiting_cpf', newContext: { ...context, name }, handled: true }
      }
    } else if (currentState === 'awaiting_cpf') {
      if (!isValidCPF(incomingText)) {
        routerResult = { response: '❌ CPF inválido. Por favor, informe um CPF válido (somente números):', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: 'CPF registrado ✅\n\nQual sua *data de nascimento*? (DD/MM/AAAA)', newState: 'awaiting_birth_date', newContext: { ...context, cpf: incomingText.replace(/\D/g,'') }, handled: true }
      }
    } else if (currentState === 'awaiting_birth_date') {
      const dateRegex = /^(\d{2})\/(\d{2})\/(\d{4})$/
      if (!dateRegex.test(incomingText)) {
        routerResult = { response: '❌ Data inválida. Use o formato DD/MM/AAAA:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: 'Data registrada ✅\n\nQual seu *estado civil*?\n\n1️⃣ Solteiro(a)\n2️⃣ Casado(a)\n3️⃣ Divorciado(a)\n4️⃣ Viúvo(a)\n5️⃣ União Estável', newState: 'awaiting_civil_status', newContext: { ...context, birthDate: incomingText }, handled: true }
      }
    } else if (currentState === 'awaiting_civil_status') {
      const status = CIVIL_STATUS_MAP[incomingText]
      if (!status) {
        routerResult = { response: '❌ Opção inválida. Escolha de 1 a 5:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: 'Registrado ✅\n\nQual seu *e-mail*?', newState: 'awaiting_email', newContext: { ...context, civilStatus: status }, handled: true }
      }
    } else if (currentState === 'awaiting_email') {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
      if (!emailRegex.test(incomingText)) {
        routerResult = { response: '❌ E-mail inválido. Por favor, informe um e-mail válido:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: 'E-mail registrado ✅\n\nEm qual *cidade* você mora?', newState: 'awaiting_city', newContext: { ...context, email: incomingText }, handled: true }
      }
    } else if (currentState === 'awaiting_city') {
      if (incomingText.length < 2) {
        routerResult = { response: '❌ Por favor, informe o nome da cidade:', newState: currentState, newContext: context, handled: true }
      } else {
        const city = incomingText.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ')
        routerResult = { response: `${city} ✅\n\nQual o *estado* (UF)? Ex: SP, RJ, MG`, newState: 'awaiting_state', newContext: { ...context, city }, handled: true }
      }
    } else if (currentState === 'awaiting_state') {
      const uf = incomingText.toUpperCase().trim()
      if (!VALID_STATES.includes(uf)) {
        routerResult = { response: '❌ UF inválida. Informe a sigla do estado (ex: SP, RJ, MG):', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${uf} ✅\n\nQual sua *renda mensal bruta*? (ex: 5000 ou 5.000,00)`, newState: 'awaiting_monthly_income', newContext: { ...context, state: uf }, handled: true }
      }
    }
  }
}

// FinancialDataHandler
if (!routerResult && (currentState === 'awaiting_monthly_income' || currentState === 'awaiting_family_income')) {
  if (currentState === 'awaiting_monthly_income') {
    const amount = parseAmount(incomingText)
    if (isNaN(amount) || amount <= 0) {
      routerResult = { response: '❌ Valor inválido. Informe sua renda mensal (ex: 5000):', newState: currentState, newContext: context, handled: true }
    } else {
      const nextState = ['imobiliario','veiculo','pessoal','consignado','empresa','equipamento','rural'].includes(context.financingType) ? 'awaiting_family_income' : 'awaiting_family_income'
      routerResult = { response: `Renda registrada ✅\n\nQual a *renda familiar total*? (incluindo cônjuge, se houver)\n(ex: 8000 ou "mesma" se for igual)`, newState: nextState, newContext: { ...context, monthlyIncome: amount }, handled: true }
    }
  } else if (currentState === 'awaiting_family_income') {
    let familyIncome
    if (incomingText === 'mesma' || incomingText === 'mesmo') {
      familyIncome = context.monthlyIncome
    } else {
      familyIncome = parseAmount(incomingText)
    }
    if (isNaN(familyIncome) || familyIncome <= 0) {
      routerResult = { response: '❌ Valor inválido. Informe a renda familiar:', newState: currentState, newContext: context, handled: true }
    } else {
      const ft = context.financingType
      let nextState, nextMsg
      if (ft === 'imobiliario') {
        nextState = 'awaiting_fgts'
        nextMsg = 'Você possui saldo de *FGTS* para usar na entrada?\n\n1️⃣ Sim\n2️⃣ Não'
      } else if (ft === 'veiculo') {
        nextState = 'awaiting_vehicle_type'
        nextMsg = 'Qual tipo de veículo?\n\n1️⃣ Carro\n2️⃣ Moto\n3️⃣ Caminhão\n4️⃣ Outro'
      } else {
        nextState = 'awaiting_loan_amount'
        nextMsg = 'Qual o *valor* que você precisa? (ex: 10000)'
      }
      routerResult = { response: `Renda familiar registrada ✅\n\n${nextMsg}`, newState: nextState, newContext: { ...context, familyIncome }, handled: true }
    }
  }
}

// ImmovableHandler
if (!routerResult) {
  const imobStates = ['awaiting_fgts','awaiting_fgts_amount','awaiting_down_payment','awaiting_down_payment_amount','awaiting_property_value','awaiting_property_type','awaiting_property_city','awaiting_property_state']
  if (imobStates.includes(currentState) && context.financingType === 'imobiliario') {
    if (currentState === 'awaiting_fgts') {
      if (incomingText === '1' || /^sim/i.test(incomingText)) {
        routerResult = { response: 'Qual o saldo aproximado do seu *FGTS*? (ex: 15000)', newState: 'awaiting_fgts_amount', newContext: context, handled: true }
      } else {
        routerResult = { response: 'Ok, sem FGTS.\n\nVocê tem *entrada* disponível (além do FGTS)?\n\n1️⃣ Sim\n2️⃣ Não', newState: 'awaiting_down_payment', newContext: { ...context, fgtsAmount: 0 }, handled: true }
      }
    } else if (currentState === 'awaiting_fgts_amount') {
      const fgtsAmount = parseAmount(incomingText)
      if (isNaN(fgtsAmount) || fgtsAmount <= 0) {
        routerResult = { response: '❌ Valor inválido. Informe o saldo do FGTS:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `FGTS: ${formatCurrency(fgtsAmount)} ✅\n\nVocê tem *entrada adicional* disponível?\n\n1️⃣ Sim\n2️⃣ Não`, newState: 'awaiting_down_payment', newContext: { ...context, fgtsAmount }, handled: true }
      }
    } else if (currentState === 'awaiting_down_payment') {
      if (incomingText === '1' || /^sim/i.test(incomingText)) {
        routerResult = { response: 'Qual o valor da *entrada*? (ex: 30000)', newState: 'awaiting_down_payment_amount', newContext: context, handled: true }
      } else {
        routerResult = { response: 'Ok.\n\nQual o *valor do imóvel*? (ex: 300000)', newState: 'awaiting_property_value', newContext: { ...context, downPaymentAmount: 0 }, handled: true }
      }
    } else if (currentState === 'awaiting_down_payment_amount') {
      const dpAmount = parseAmount(incomingText)
      if (isNaN(dpAmount) || dpAmount <= 0) {
        routerResult = { response: '❌ Valor inválido. Informe o valor da entrada:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `Entrada: ${formatCurrency(dpAmount)} ✅\n\nQual o *valor do imóvel*? (ex: 300000)`, newState: 'awaiting_property_value', newContext: { ...context, downPaymentAmount: dpAmount }, handled: true }
      }
    } else if (currentState === 'awaiting_property_value') {
      const propertyValue = parseAmount(incomingText)
      if (isNaN(propertyValue) || propertyValue <= 0) {
        routerResult = { response: '❌ Valor inválido. Informe o valor do imóvel:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${formatCurrency(propertyValue)} ✅\n\nQual o *tipo do imóvel*?\n\n1️⃣ Residencial\n2️⃣ Comercial\n3️⃣ Terreno\n4️⃣ Rural`, newState: 'awaiting_property_type', newContext: { ...context, propertyValue }, handled: true }
      }
    } else if (currentState === 'awaiting_property_type') {
      const propertyType = PROPERTY_TYPE_MAP[incomingText]
      if (!propertyType) {
        routerResult = { response: '❌ Opção inválida. Escolha de 1 a 4:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${propertyType} ✅\n\nEm qual *cidade* fica o imóvel?`, newState: 'awaiting_property_city', newContext: { ...context, propertyType }, handled: true }
      }
    } else if (currentState === 'awaiting_property_city') {
      const propertyCity = incomingText.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ')
      routerResult = { response: `${propertyCity} ✅\n\nQual o *estado* do imóvel? (UF)`, newState: 'awaiting_property_state', newContext: { ...context, propertyCity }, handled: true }
    } else if (currentState === 'awaiting_property_state') {
      const uf = incomingText.toUpperCase().trim()
      if (!VALID_STATES.includes(uf)) {
        routerResult = { response: '❌ UF inválida. Informe a sigla (ex: SP, RJ):', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${uf} ✅\n\nPor quanto tempo você quer financiar?\n\n1️⃣ 12 meses\n2️⃣ 24 meses\n3️⃣ 36 meses\n4️⃣ 48 meses\n5️⃣ 60 meses\n\nOu informe o número de meses (6 a 420):`, newState: 'awaiting_term', newContext: { ...context, propertyState: uf }, handled: true }
      }
    }
  }
}

// VehicleHandler
if (!routerResult) {
  const vehicleStates = ['awaiting_vehicle_type','awaiting_vehicle_value','awaiting_vehicle_year','awaiting_vehicle_down_payment']
  if (vehicleStates.includes(currentState) && context.financingType === 'veiculo') {
    if (currentState === 'awaiting_vehicle_type') {
      const vehicleType = VEHICLE_TYPE_MAP[incomingText]
      if (!vehicleType) {
        routerResult = { response: '❌ Opção inválida. Escolha de 1 a 4:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${vehicleType} ✅\n\nQual o *valor do veículo*? (ex: 50000)`, newState: 'awaiting_vehicle_value', newContext: { ...context, vehicleType }, handled: true }
      }
    } else if (currentState === 'awaiting_vehicle_value') {
      const vehicleValue = parseAmount(incomingText)
      if (isNaN(vehicleValue) || vehicleValue <= 0) {
        routerResult = { response: '❌ Valor inválido. Informe o valor do veículo:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${formatCurrency(vehicleValue)} ✅\n\nQual o *ano do veículo*? (ex: 2022)`, newState: 'awaiting_vehicle_year', newContext: { ...context, vehicleValue }, handled: true }
      }
    } else if (currentState === 'awaiting_vehicle_year') {
      const year = parseInt(incomingText)
      if (isNaN(year) || year < 1990 || year > 2027) {
        routerResult = { response: '❌ Ano inválido. Informe um ano entre 1990 e 2027:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${year} ✅\n\nVocê tem *entrada*?\n\n1️⃣ Sim\n2️⃣ Não`, newState: 'awaiting_vehicle_down_payment', newContext: { ...context, vehicleYear: year }, handled: true }
      }
    } else if (currentState === 'awaiting_vehicle_down_payment') {
      if (incomingText === '1' || /^sim/i.test(incomingText)) {
        routerResult = { response: 'Qual o valor da *entrada*? (ex: 10000)', newState: 'awaiting_vehicle_down_payment_amount', newContext: context, handled: true }
      } else {
        routerResult = { response: `Ok, sem entrada.\n\nPor quanto tempo você quer financiar?\n\n1️⃣ 12 meses\n2️⃣ 24 meses\n3️⃣ 36 meses\n4️⃣ 48 meses\n5️⃣ 60 meses\n\nOu informe o número de meses (6 a 420):`, newState: 'awaiting_term', newContext: { ...context, downPaymentAmount: 0 }, handled: true }
      }
    }
  }
  if (!routerResult && currentState === 'awaiting_vehicle_down_payment_amount' && context.financingType === 'veiculo') {
    const dpAmount = parseAmount(incomingText)
    if (isNaN(dpAmount) || dpAmount <= 0) {
      routerResult = { response: '❌ Valor inválido. Informe o valor da entrada:', newState: currentState, newContext: context, handled: true }
    } else {
      routerResult = { response: `${formatCurrency(dpAmount)} ✅\n\nPor quanto tempo você quer financiar?\n\n1️⃣ 12 meses\n2️⃣ 24 meses\n3️⃣ 36 meses\n4️⃣ 48 meses\n5️⃣ 60 meses\n\nOu informe o número de meses (6 a 420):`, newState: 'awaiting_term', newContext: { ...context, downPaymentAmount: dpAmount }, handled: true }
    }
  }
}

// LoanHandler (pessoal, consignado, empresa, equipamento, rural)
if (!routerResult) {
  const loanTypes = ['pessoal','consignado','empresa','equipamento','rural']
  const loanStates = ['awaiting_loan_amount','awaiting_employment_type','awaiting_employer','awaiting_cnpj','awaiting_company_revenue']
  if (loanStates.includes(currentState) && loanTypes.includes(context.financingType)) {
    if (currentState === 'awaiting_loan_amount') {
      const loanAmount = parseAmount(incomingText)
      if (isNaN(loanAmount) || loanAmount <= 0) {
        routerResult = { response: '❌ Valor inválido. Informe o valor desejado:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${formatCurrency(loanAmount)} ✅\n\nQual seu *tipo de emprego*?\n\n1️⃣ CLT\n2️⃣ Servidor Público\n3️⃣ Autônomo\n4️⃣ Empresário\n5️⃣ Aposentado/Pensionista`, newState: 'awaiting_employment_type', newContext: { ...context, loanAmount }, handled: true }
      }
    } else if (currentState === 'awaiting_employment_type') {
      const employmentType = EMPLOYMENT_TYPE_MAP[incomingText]
      if (!employmentType) {
        routerResult = { response: '❌ Opção inválida. Escolha de 1 a 5:', newState: currentState, newContext: context, handled: true }
      } else if (['empresa','equipamento'].includes(context.financingType)) {
        routerResult = { response: `${employmentType} ✅\n\nQual o *CNPJ* da empresa? (somente números)`, newState: 'awaiting_cnpj', newContext: { ...context, employmentType }, handled: true }
      } else {
        routerResult = { response: `${employmentType} ✅\n\nQual o nome do seu *empregador/empresa*?`, newState: 'awaiting_employer', newContext: { ...context, employmentType }, handled: true }
      }
    } else if (currentState === 'awaiting_employer') {
      routerResult = { response: `Registrado ✅\n\nPor quanto tempo você quer o crédito?\n\n1️⃣ 12 meses\n2️⃣ 24 meses\n3️⃣ 36 meses\n4️⃣ 48 meses\n5️⃣ 60 meses\n\nOu informe o número de meses (6 a 420):`, newState: 'awaiting_term', newContext: { ...context, employer: incomingText }, handled: true }
    } else if (currentState === 'awaiting_cnpj') {
      const cnpj = incomingText.replace(/\D/g, '')
      if (cnpj.length !== 14) {
        routerResult = { response: '❌ CNPJ inválido. Informe os 14 dígitos:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `CNPJ registrado ✅\n\nQual o *faturamento mensal* da empresa?`, newState: 'awaiting_company_revenue', newContext: { ...context, cnpj }, handled: true }
      }
    } else if (currentState === 'awaiting_company_revenue') {
      const revenue = parseAmount(incomingText)
      if (isNaN(revenue) || revenue <= 0) {
        routerResult = { response: '❌ Valor inválido. Informe o faturamento mensal:', newState: currentState, newContext: context, handled: true }
      } else {
        routerResult = { response: `${formatCurrency(revenue)} ✅\n\nPor quanto tempo você quer o crédito?\n\n1️⃣ 12 meses\n2️⃣ 24 meses\n3️⃣ 36 meses\n4️⃣ 48 meses\n5️⃣ 60 meses\n\nOu informe o número de meses (6 a 420):`, newState: 'awaiting_term', newContext: { ...context, companyRevenue: revenue }, handled: true }
      }
    }
  }
}

// TermAndSimulationHandler
if (!routerResult && currentState === 'awaiting_term') {
  let termMonths = TERM_SHORTCUTS[incomingText] ?? null
  if (!termMonths) {
    const parsed = parseInt(incomingText)
    if (!isNaN(parsed) && parsed >= 6 && parsed <= 420) termMonths = parsed
  }
  if (!termMonths) {
    routerResult = { response: '❌ Prazo inválido. Informe um número entre 6 e 420 (meses):', newState: currentState, newContext: context, handled: true }
  } else {
    const requestedAmount = context.propertyValue ?? context.vehicleValue ?? context.loanAmount ?? 0
    const downPaymentAmount = context.downPaymentAmount ?? 0
    const fgtsAmount = context.fgtsAmount ?? 0
    routerResult = {
      response: `⏳ Calculando simulação para *${context.name}*...\n\nConsultando taxas dos principais bancos do mercado.`,
      newState: 'simulation_ready',
      newContext: { ...context, termMonths, requestedAmount, downPaymentAmount, fgtsAmount },
      triggerSimulation: true,
      simulationPayload: {
        whatsappNumber: phone,
        financingType: context.financingType,
        requestedAmount,
        downPaymentAmount,
        fgtsAmount,
        termMonths,
        propertyValue: context.propertyValue,
        propertyType: context.propertyType,
        propertyCity: context.propertyCity,
        propertyState: context.propertyState,
        vehicleType: context.vehicleType,
        vehicleYear: context.vehicleYear,
        metadata: {
          employmentType: context.employmentType,
          employer: context.employer,
          cnpj: context.cnpj,
          companyRevenue: context.companyRevenue,
        },
      },
      handled: true,
    }
  }
}

// SimulationResultHandler
if (!routerResult && currentState === 'simulation_ready') {
  if (incomingText === '1' || /^sim/i.test(incomingText)) {
    routerResult = {
      response: '👨‍💼 Ótimo! Um de nossos consultores entrará em contato em breve.\n\nObrigado por confiar em nós! 🏠',
      newState: 'human_handoff',
      newContext: context,
      triggerHandoff: true,
      handled: true,
    }
  } else if (incomingText === '2' || /^n[ãa]o/i.test(incomingText)) {
    routerResult = {
      response: '😊 Obrigado! Se precisar de mais simulações ou tiver dúvidas, é só enviar "oi".',
      newState: 'completed',
      newContext: context,
      handled: true,
    }
  } else if (isGreeting) {
    routerResult = {
      response: '👋 Olá! Seja bem-vindo ao simulador de financiamentos!\n\nQual modalidade você precisa?\n\n1️⃣ Imóvel\n2️⃣ Veículo\n3️⃣ Crédito Pessoal\n4️⃣ Consignado\n5️⃣ Empresa/PJ\n6️⃣ Equipamento\n7️⃣ Rural/Agrícola',
      newState: 'awaiting_financing_type',
      newContext: {},
      handled: true,
    }
  }
}

// Fallback
if (!routerResult) {
  routerResult = {
    response: 'Desculpe, não entendi sua mensagem. Envie "oi" para recomeçar ou "cancelar" para sair.',
    newState: currentState,
    newContext: context,
    handled: true,
  }
}

return [{
  json: {
    phone,
    response: routerResult.response,
    newState: routerResult.newState,
    newContext: routerResult.newContext,
    triggerSimulation: routerResult.triggerSimulation ?? false,
    simulationPayload: routerResult.simulationPayload ?? null,
    triggerHandoff: routerResult.triggerHandoff ?? false,
    handoffData: routerResult.triggerHandoff ? {
      phone,
      name: routerResult.newContext?.name,
      financingType: routerResult.newContext?.financingType,
      simulationId: routerResult.newContext?.simulationId,
    } : null,
    businessPhone: messageData.businessPhone,
  }
}]

const routerData = $('Rotear e Responder').first().json
const simResult = $input.first().json

let responseText = routerData.response + '\n\n'

if (simResult?.results?.length > 0) {
  responseText += '📊 *Resultados da Simulação*\n\n'
  simResult.results.slice(0, 5).forEach((r, i) => {
    const emoji = ['🥇','🥈','🥉','4️⃣','5️⃣'][i]
    const bank = r.bankName ?? 'Banco'
    responseText += `${emoji} *${bank}*\n`
    if (r.amortizationSystem === 'SAC') {
      responseText += `   SAC: 1ª parcela ${new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(r.firstInstallment)}\n`
      responseText += `   Última: ${new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(r.lastInstallment)}\n`
    } else {
      responseText += `   PRICE: ${new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(r.fixedInstallment)}/mês\n`
    }
    responseText += `   Taxa: ${(r.annualRate * 100).toFixed(2)}% a.a.\n`
    responseText += `   CET: ${(r.cetAnnual * 100).toFixed(2)}% a.a.\n\n`
  })
  responseText += '---\nDeseja falar com um consultor para mais detalhes?\n\n1️⃣ Sim, quero falar com um consultor\n2️⃣ Não, obrigado'
} else {
  responseText += '⚠️ Não foi possível calcular a simulação no momento. Um consultor entrará em contato.'
}

return [{
  json: {
    ...routerData,
    response: responseText,
    simulationId: simResult?.id,
  }
}]
